<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        useBuiltIns: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;usage&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 极其重要：按需按实际使用情况引入 Polyfill</span></span>
